// 1. Recebe dados da IA e Token do Login
const input = $('Configuracao2').first().json;
const token = $("Login Dinamico").first().json.token;

// 2. Mapeamento de Enums
const bidOperations = { "compra": 1, "venda": 2 };
const currencies = { "BRL": 2, "USD": 3, "EU": 1 };

// 3. Organiza o payload para os próximos nós
return {
  token: token,
    operationId: bidOperations[input.operacao?.toLowerCase()] || 1,
    product_name: input.produto,
    quantity: input.quantidade,
    price: input.preco,
    city_name: input.cidade,
    state_uf: input.estado?.toUpperCase(),
    duration: `${(input.periodo || 7) * 24}:00`,
    currencyId: currencies[input.moeda?.toUpperCase()] || 2
};

