(() => {
  const lista = $( "Listar Unidade Medida1" ).all().map(i => i.json);
  const unidadeDaIA = $('When Executed by Another Workflow').item.json.unidade;
  const buscaIA = ( unidadeDaIA || "" ).toLowerCase();

  const encontrado = lista.find(item => {
    const nomeUnidade = (item.translations?.pt || "").toLowerCase();
    return nomeUnidade.includes(buscaIA) || buscaIA.includes(nomeUnidade);
  });

  if (!encontrado) {
    // Isso vai forçar o nó a dar erro e parar a execução
    throw new Error(`Unidade '${unidadeDaIA}' não encontrada para este produto. Opções válidas: ${lista.map(i => i.translations?.pt).join(", ")}`);
  }

  return encontrado.id; 
})()
}}

